SELECT id, category_id, title, content, keywords, tags, status, current_version, created_at, updated_at, deleted FROM steering WHERE deleted = false AND status = 'active' AND to_tsvector('simple', coalesce(title,'') || ' ' || coalesce(content,'') || ' ' || coalesce(keywords,'')) @@ plainto_tsquery('simple', #{query})
AND category_id = #{categoryId}
ORDER BY ts_rank( to_tsvector('simple', coalesce(title,'') || ' ' || coalesce(content,'') || ' ' || coalesce(keywords,'')), plainto_tsquery('simple', #{query}) ) DESC LIMIT #{limit}

SELECT s.*, (1 - (s.embedding <=> #{embedding}::vector)) AS similarity_score FROM steering s WHERE s.deleted = false AND s.status = 'active' AND s.embedding IS NOT NULL AND (1 - (s.embedding <=> #{embedding}::vector)) > 0.3
AND s.category_id = #{categoryId}
ORDER BY s.embedding <=> #{embedding}::vector LIMIT #{limit}
